#include <iostream>

int main() {
    int arr[] = {1, 2, 3, 4, 5};
    int* ptr = arr;
    int*& refPtr = ptr;

    std::cout << *ptr << " ";      // 1
    std::cout << *ptr++ << " ";    // 1
    std::cout << *ptr << " ";      // 2

    std::cout << *++ptr << " ";    // 3
    std::cout << (*ptr)++ << " ";  // 3
    std::cout << *ptr << " ";      // 4 (what about the increment?)

    refPtr++;
    std::cout << *refPtr << " ";  // ?

    return 0;
}

